import{_ as e,c as a,o,V as t}from"./chunks/framework.CA_7cDmG.js";const u=JSON.parse('{"title":"安裝vscode","description":"","frontmatter":{},"headers":[],"relativePath":"python/新手上路系列/安裝vscode.md","filePath":"python/新手上路系列/安裝vscode.md","lastUpdated":1712487480000}'),d={name:"python/新手上路系列/安裝vscode.md"},c=t('<h1 id="安裝vscode" tabindex="-1">安裝vscode <a class="header-anchor" href="#安裝vscode" aria-label="Permalink to &quot;安裝vscode&quot;">​</a></h1><p>到<a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">官網</a>點donwload(下載)<br> 然後就啟動<br> 一直按下一步<br> 最後面的 按右鍵以code開啟 這個選項可以抅</p><h1 id="開啟vscode" tabindex="-1">開啟vscode <a class="header-anchor" href="#開啟vscode" aria-label="Permalink to &quot;開啟vscode&quot;">​</a></h1><p>然後在左邊會看到這些選項，去點四個方塊的那個 就是圖片中第5個icon <img src="https://hackmd.io/_uploads/HyornA_Mp.png" alt="" loading="lazy"></p><p>按下去 然後在搜尋框打中文</p><p>install 是下載的意思 uninstall 是解除安裝的意思 <img src="https://hackmd.io/_uploads/rJ8FdzEta.png" alt="image" loading="lazy"></p><p>然後右下角會跳出訊息 問你要不要改語言 <img src="https://hackmd.io/_uploads/S1ms_M4F6.png" alt="image" loading="lazy"> 當然是直接點擊<code>Change Language and Restart</code></p><h1 id="開始連結資料夾" tabindex="-1">開始連結資料夾 <a class="header-anchor" href="#開始連結資料夾" aria-label="Permalink to &quot;開始連結資料夾&quot;">​</a></h1><p>創一個空的資料夾 在到vscode的左上角點擊【檔案】 然後可以找到【開啟資料夾】的選項 <img src="https://hackmd.io/_uploads/BkvMqGVF6.png" alt="image" loading="lazy"></p><p>選擇剛剛建好的資料夾 按【選擇資料夾】</p><h2 id="可以安裝的掛件" tabindex="-1">可以安裝的掛件 <a class="header-anchor" href="#可以安裝的掛件" aria-label="Permalink to &quot;可以安裝的掛件&quot;">​</a></h2><ul><li>如果要用python就在搜尋框打<code>python</code>然後就點install</li><li>做網頁就可以去找<code>live server</code></li><li><code>cdnjs</code>引入套件很好用</li><li><code>Vitesse theme</code> 的顏色好看(按<code>ctrl</code> + <code>shift</code> + <code>p</code> 然後打<code>Color Theme</code> 可以自己調顏色)</li></ul>',12),s=[c];function l(i,r,n,p,h,_){return o(),a("div",null,s)}const g=e(d,[["render",l]]);export{u as __pageData,g as default};
